import { useState } from "react";
// import { recipes } from "../../data/index"; // Assume this is the correct path for mock data or use props

const NAV = [
  { icon: "📊", label: "Dashboard", id: "overview" },
  { icon: "👨‍🍳", label: "My Creations", id: "creations", active: true },
  { icon: "📈", label: "Analytics", id: "analytics" },
  { icon: "👥", label: "Followers", id: "followers" },
];

const TABS = ["All Recipes", "Live", "Pending Review", "Rejected"];

const STATUS_BADGE = {
  Live: "badge-live",
  "Pending Review": "badge-pending",
  Rejected: "badge-rejected",
};

// Mock recipes for demonstration if not provided
const mockRecipes = [
  { id: 1, title: "Truffle Risotto", status: "Live", updatedAgo: "2 days ago", image: "https://images.unsplash.com/photo-1476124369491-e7addf5db371?w=400&h=250&fit=crop" },
  { id: 2, title: "Spicy Arrabbiata", status: "Pending Review", updatedAgo: "5 hours ago", image: "https://images.unsplash.com/photo-1551183053-bf91a1d81141?w=400&h=250&fit=crop" },
  { id: 3, title: "Vegan Buddha Bowl", status: "Rejected", updatedAgo: "yesterday", image: "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=400&h=250&fit=crop" },
  { id: 4, title: "Classic Avocado Toast", status: "Live", updatedAgo: "1 week ago", image: "https://images.unsplash.com/photo-1525351484163-7529414344d8?w=400&h=250&fit=crop" },
];

export default function ChefDashboardPage({ setPage, setSelectedRecipe }) {
  const [activeNav, setActiveNav] = useState("creations");
  const [activeTab, setActiveTab] = useState("All Recipes");

  const filtered = activeTab === "All Recipes" ? mockRecipes : mockRecipes.filter(r => r.status === activeTab);

  return (
    <div className="sidebar-layout">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <div style={{ padding: "0 8px 32px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "32px" }}>
            <div style={{ width: "32px", height: "32px", background: "var(--primary)", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "16px", color: "#fff" }}>🍽</div>
            <span className="serif" style={{ fontSize: "18px", fontWeight: "700", color: "var(--navy)" }}>RecipeNest</span>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: "4px" }}>
            {NAV.map(item => (
              <button 
                key={item.id} 
                className={`sidebar-item ${activeNav === item.id ? "active" : ""}`} 
                onClick={() => setActiveNav(item.id)}
              >
                <span style={{ fontSize: "18px" }}>{item.icon}</span>
                {item.label}
              </button>
            ))}
          </div>
        </div>

        <div style={{ marginTop: "auto", padding: "20px 8px 0", borderTop: "1px solid var(--border-light)" }}>
          <button className="sidebar-item" style={{ marginBottom: "16px" }}>
            <span style={{ fontSize: "18px" }}>⚙️</span> Settings
          </button>

          <div style={{ display: "flex", alignItems: "center", gap: "12px", padding: "12px", background: "#f8fafc", borderRadius: "var(--radius-md)", marginBottom: "16px" }}>
            <div className="sidebar-avatar" style={{ width: "40px", height: "40px" }}>CM</div>
            <div>
              <div style={{ fontSize: "13px", fontWeight: "700", color: "var(--text-main)" }}>Chef Mario</div>
              <div style={{ fontSize: "11px", color: "var(--text-muted)" }}>Master Chef</div>
            </div>
          </div>

          <button className="logout-btn" onClick={() => setPage("home")}>
            <span>🚪</span> Logout
          </button>
        </div>
      </aside>

      {/* DASHBOARD CONTENT */}
      <main className="page-content" style={{ background: "#fdfdfd" }}>
        <div className="page-header" style={{ marginBottom: "40px" }}>
          <div>
            <h1 className="page-title">My Creations</h1>
            <p className="page-sub">Manage your portfolio and track how your recipes are performing.</p>
          </div>
          <button className="action-cta" style={{ filter: "drop-shadow(0 4px 12px rgba(255, 49, 49, 0.2))" }}>
            <span style={{ fontSize: "18px" }}>+</span> Create New Recipe
          </button>
        </div>

        {/* Stats Row */}
        <div className="stats-row" style={{ marginBottom: "48px" }}>
          {[
            { label: "Total Followers", val: "12.5k", icon: "👥", bg: "#eff6ff", color: "#3b82f6" },
            { label: "Recipe Likes", val: "45.8k", icon: "❤️", bg: "#fef2f2", color: "#ef4444" },
            { label: "Average Rating", val: "4.8", icon: "⭐", bg: "#fefce8", color: "#eab308" }
          ].map((stat, i) => (
            <div key={i} className="stat-card" style={{ border: "1px solid var(--border-light)", boxShadow: "var(--shadow-sm)" }}>
              <div className="stat-icon" style={{ background: stat.bg, color: stat.color }}>{stat.icon}</div>
              <div>
                <div className="stat-val">{stat.val}</div>
                <div className="stat-label">{stat.label}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div className="tab-bar" style={{ marginBottom: "32px", borderBottom: "1px solid #f1f5f9" }}>
          {TABS.map(tab => (
            <button 
              key={tab} 
              className={`tab-btn ${activeTab === tab ? "active" : ""}`} 
              onClick={() => setActiveTab(tab)}
              style={{ padding: "12px 24px" }}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* Recipe Grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "24px" }}>
          {filtered.map(recipe => (
            <div 
              key={recipe.id} 
              className="card-hover"
              style={{ background: "#fff", borderRadius: "var(--radius-lg)", overflow: "hidden", border: "1px solid var(--border-light)", cursor: "pointer" }}
            >
              <div style={{ position: "relative", height: "180px" }}>
                <img src={recipe.image} alt={recipe.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                <span className={`badge ${STATUS_BADGE[recipe.status]}`} style={{ position: "absolute", top: "12px", left: "12px", border: "1px solid rgba(0,0,0,0.05)" }}>
                  ● {recipe.status}
                </span>
              </div>
              <div style={{ padding: "20px" }}>
                <h3 style={{ fontSize: "16px", fontWeight: "700", color: "var(--text-main)", marginBottom: "4px" }}>{recipe.title}</h3>
                <p style={{ fontSize: "12px", color: "var(--text-muted)" }}>Updated {recipe.updatedAgo}</p>
              </div>
              <div style={{ display: "flex", gap: "8px", padding: "0 20px 20px" }}>
                {[
                  { icon: "✏️", label: "Edit" },
                  { icon: "📊", label: "Stats" },
                  { icon: "🗑️", label: "Delete" }
                ].map(action => (
                  <button 
                    key={action.label}
                    style={{ 
                      flex: 1, 
                      background: "#f8fafc", 
                      border: "1px solid #f1f5f9", 
                      padding: "8px", 
                      borderRadius: "8px", 
                      fontSize: "14px",
                      transition: "all 0.2s"
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = "#fff1f1"}
                    onMouseLeave={e => e.currentTarget.style.background = "#f8fafc"}
                  >
                    {action.icon}
                  </button>
                ))}
              </div>
            </div>
          ))}

          {/* New Draft Placeholder */}
          <div style={{ 
            background: "#fff", 
            border: "2px dashed #e2e8f0", 
            borderRadius: "var(--radius-lg)", 
            display: "flex", 
            flexDirection: "column", 
            alignItems: "center", 
            justifyContent: "center", 
            minHeight: "300px", 
            padding: "40px",
            textAlign: "center"
          }}>
            <div style={{ width: "56px", height: "56px", background: "#f8fafc", borderRadius: "16px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "24px", marginBottom: "20px" }}>➕</div>
            <h3 style={{ fontSize: "16px", fontWeight: "700", color: "var(--text-main)", marginBottom: "8px" }}>New Idea?</h3>
            <p style={{ fontSize: "13px", color: "var(--text-muted)", marginBottom: "24px", lineHeight: "1.5" }}>Start drafting your next culinary masterpiece and share it with the world.</p>
            <button className="btn-secondary" style={{ padding: "8px 24px", fontSize: "13px" }}>New Draft</button>
          </div>
        </div>
      </main>
    </div>
  );
}
